    use super::*;

    /// Collect every `ToolbarButton::Action` label from a toolbar.
    /// Test-only convenience for assertions that previously walked
    /// `bar.left_segments` on the StatusBar shape.
    fn toolbar_action_labels(bar: &Toolbar) -> Vec<String> {
        bar.buttons
            .iter()
            .filter_map(|b| match b {
                ToolbarButton::Action { label, .. } => Some(label.clone()),
                _ => None,
            })
            .collect()
    }

    // ── #584/#748: /board payload deserialization ────────────────────────────

    /// Deserialize the committed golden `/board` fixture
    /// (`tui/tests/fixtures/board_sample.json`, generated by
    /// `scripts/gen_board_fixture.py` from a freshly-migrated DB) into a
    /// `BoardPayload` and assert the serde renames + custom deserializers
    /// work.
    ///
    /// #748: this used to read `/tmp/584/board_sample.json` and silently
    /// no-op when absent — which meant it never ran in CI, so the very next
    /// SQLite `INTEGER`-as-bool column added without a deserializer guard
    /// would have shipped unguarded straight into the #632 blank-board class.
    /// The fixture is now checked into the repo so this is a hard assertion
    /// that runs on every `cargo test` (gated in CI by
    /// `.github/workflows/cargo-test.yml`). The identical fixture bytes are
    /// also asserted fresh on the Python producer side in
    /// `tests/test_board_fixture.py::test_board_sample_fixture_is_up_to_date`.
    #[test]
    fn board_payload_deserializes_real_sample() {
        let s = std::fs::read_to_string(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/tests/fixtures/board_sample.json"
        ))
        .expect("committed golden fixture tui/tests/fixtures/board_sample.json must be readable");
        let payload: BoardPayload =
            serde_json::from_str(&s).expect("real /board sample must deserialize into BoardPayload");

        // round_number is carried through from the top-level key.
        assert_eq!(payload.round_number, 3, "round_number should match the sample");

        // assignments populated, and the renames map DB columns → short fields.
        assert!(!payload.assignments.is_empty(), "assignments must be non-empty");
        let a = &payload.assignments[0];
        assert!(!a.id.is_empty(), "assignment id (rename assignment_id) populated");
        assert!(!a.repo.is_empty(), "repo (rename repo_name) populated");
        assert!(
            !a.machine.is_empty(),
            "machine (rename machine_name) populated"
        );
        assert!(
            a.assignment_type.is_some(),
            "assignment_type (rename type) populated"
        );

        // At least one assignment carries a parsed smoke_tests array.
        assert!(
            payload.assignments.iter().any(|a| a.smoke_tests.is_some()),
            "at least one assignment should have smoke_tests"
        );

        // Machines decode into RawMachine (name/host/repos).
        assert!(!payload.machines.is_empty(), "machines must be non-empty");
        assert!(
            payload.machines.iter().all(|m| !m.name.is_empty()),
            "every machine has a name"
        );
    }

    #[test]
    fn board_payload_parses_int_valued_is_interactive() {
        // #628 hotfix: the daemon serializes the SQLite boolean is_interactive
        // as an int (0/1). A strict `bool` field used to fail the WHOLE
        // BoardPayload parse on `is_interactive:0`, returning an empty board and
        // blanking every panel. The payload must parse and the field coerce.
        let json = r#"{
            "assignments": [
                {"assignment_id":"a1","machine_name":"m","repo_name":"r","issue_number":1,
                 "issue_title":"t","status":"running","type":"work","is_interactive":0},
                {"assignment_id":"a2","machine_name":"m","repo_name":"r","issue_number":2,
                 "issue_title":"t","status":"done","type":"work","is_interactive":1}
            ],
            "machines": [{"name":"m","host":"h","repos":[]}]
        }"#;
        let payload: BoardPayload =
            serde_json::from_str(json).expect("int-valued is_interactive must not fail the parse");
        assert_eq!(payload.assignments.len(), 2, "every row parsed (no whole-payload failure)");
        assert!(!payload.assignments[0].is_interactive, "0 → false");
        assert!(payload.assignments[1].is_interactive, "1 → true");
        assert_eq!(payload.machines.len(), 1);
    }

    /// The custom `test_plan` deserializer must turn the OBJECT wire shape
    /// `{"steps":[...]}` into `Some(vec_of_steps)` (NOT treat it as an array).
    #[test]
    fn test_plan_object_deserializes_to_steps() {
        let raw = r#"{
            "assignment_id": "abc123",
            "repo_name": "demo",
            "machine_name": "m1",
            "issue_number": 7,
            "issue_title": "t",
            "status": "done",
            "test_plan": {"steps": [{"kind": "run", "cmd": "x"}]}
        }"#;
        let a: Assignment = serde_json::from_str(raw).expect("assignment with object test_plan");
        let steps = a.test_plan.expect("test_plan should be Some");
        assert_eq!(steps.len(), 1);
        assert_eq!(steps[0].kind, "run");
        assert_eq!(steps[0].cmd.as_deref(), Some("x"));
        assert!(steps[0].check.is_none());
    }

    /// A null / absent test_plan stays None (graceful degradation).
    #[test]
    fn test_plan_absent_is_none() {
        let raw = r#"{
            "assignment_id": "abc123",
            "repo_name": "demo",
            "machine_name": "m1",
            "issue_number": 7,
            "issue_title": "t",
            "status": "done"
        }"#;
        let a: Assignment = serde_json::from_str(raw).expect("assignment without test_plan");
        assert!(a.test_plan.is_none());
    }

