    #[test]
    fn pipeline_groups_for_repo_folds_refining_into_new() {
        // #628: Refining is eliminated — the Pipeline surfaces New / Pending /
        // In-progress / Done. A legacy `status:refining` label folds into New.
        let mut app = make_pipeline_app();
        // Issue #42 has status:ready → Pending (already visible).
        // Add issue #43 with no labels → "new" classifier → New section.
        app.pipeline_issues.push(PipelineIssue {
            number: 43,
            title: "Backlog".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        });
        // Issue #44 with a legacy status:refining label → folds into New (#628).
        app.pipeline_issues.push(PipelineIssue {
            number: 44,
            title: "Legacy refining".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:refining".to_string()],
            is_closed: false,
        });

        let groups = app.pipeline_groups_for_repo("api");
        // #628: status:ready / status:refining gate nothing, so every
        // coord-tracked pre-work issue is "new" — a single section. #42
        // (status:ready), #43 (no label), #44 (status:refining) all land in New.
        let keys: Vec<&str> = groups.iter().map(|(k, _)| *k).collect();
        assert_eq!(keys, vec!["new"]);
        let mut new_issues: Vec<u64> = groups[0]
            .1
            .iter()
            .map(|i| app.pipeline_issues[*i].number)
            .collect();
        new_issues.sort();
        assert_eq!(new_issues, vec![42, 43, 44]);
    }

    #[test]
    fn pipeline_groups_for_repo_visible_section_order() {
        // #628: visible sections render in display order New → In-progress →
        // Done. #42 (status:ready) is now "new" (status:ready gates nothing).
        let mut app = make_pipeline_app();
        // #42 already has status:ready → New.
        // Add #43 with status:ready + an assignment → In-progress.
        app.pipeline_issues.push(PipelineIssue {
            number: 43,
            title: "Active".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:ready".to_string()],
            is_closed: false,
        });
        app.data
            .assignments
            .push(make_assignment_typed("running", 43, "api", Some("work")));
        // Add #44 as closed with an assignment → Done.
        app.pipeline_issues.push(PipelineIssue {
            number: 44,
            title: "Finished".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:ready".to_string()],
            is_closed: true,
        });
        app.data
            .assignments
            .push(make_assignment_typed("done", 44, "api", Some("work")));

        let groups = app.pipeline_groups_for_repo("api");
        let order: Vec<&str> = groups.iter().map(|(k, _)| *k).collect();
        assert_eq!(order, vec!["new", "in-progress", "done"]);
    }

    /// #628: the production `rebuild_pipeline_sidebar` path exposes the THREE
    /// lifecycle sections in canonical order New → In-progress → Done. Neither
    /// status:ready (Pending) nor status:refining (Refining) splits a bucket —
    /// they gate nothing — so both fold into New.
    #[test]
    fn rebuild_pipeline_sidebar_exposes_three_lifecycle_sections() {
        let mut app = make_pipeline_app();
        // The fixture starts with two issues, both `status:ready`
        // (Pending).  Add one issue per remaining state.
        // New: no `status:*` label.
        app.pipeline_issues.push(PipelineIssue {
            number: 101,
            title: "Brand new".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        });
        // Legacy `status:refining` → folds into New (#628, Refining eliminated).
        app.pipeline_issues.push(PipelineIssue {
            number: 102,
            title: "Legacy refining".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:refining".to_string()],
            is_closed: false,
        });
        // In-progress: status:ready + active work assignment.
        app.pipeline_issues.push(PipelineIssue {
            number: 103,
            title: "Actively working".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:ready".to_string()],
            is_closed: false,
        });
        app.data
            .assignments
            .push(make_assignment_typed("running", 103, "api", Some("work")));
        // Done: closed.
        app.pipeline_issues.push(PipelineIssue {
            number: 104,
            title: "Closed".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: true,
        });
        // #728: issue #104 has no finished_at; use All window so it appears.
        app.done_window = DoneWindow::All;
        app.rebuild_pipeline_sidebar(None);

        // #815: In-progress moves to the top; the pre-dispatch states follow.
        // status:ready and status:refining gate nothing, so the fixture's
        // status:ready issues + #101 (no label) + #102 (status:refining) all
        // sit in New.  Order is: In-progress → New → Done.
        assert_eq!(
            app.pipeline_state_section_names,
            vec!["in-progress", "new", "done"],
            "In-progress must appear first (#815), followed by New then Done",
        );
    }

