    // ── #897: headless running assignments → Live ─────────────────────────────

    #[test]
    fn headless_running_work_classifies_as_live() {
        // #897: a headless (is_interactive=false) `claude -p` work assignment
        // with status="running" must place the issue in the Live group even
        // though no tmux session exists.  Previously it fell through to Idle
        // because `issue_session_is_live` only checked `live_tmux_sessions`.
        let mut app = make_pipeline_app();
        let mut a = make_assignment_typed("running", 42, "api", Some("work"));
        a.is_interactive = false;
        app.data.assignments.push(a);

        // Confirm no tmux session is present — the assignment is the only signal.
        assert!(app.live_tmux_sessions.is_empty());
        let groups = app.pipeline_active_by_liveness();
        assert_eq!(groups.len(), 1);
        assert_eq!(
            groups[0].0, "live",
            "headless running work assignment must render under Live, not Idle"
        );
        assert_eq!(groups[0].1.len(), 1);
    }

    #[test]
    fn headless_running_review_classifies_as_live() {
        // #897: the running-assignment check is type-agnostic — a running
        // review (non-work type) must also mark the issue as Live.
        let mut app = make_pipeline_app();
        // A done work assignment puts issue #42 in-progress (pipeline_lifecycle_section).
        app.data
            .assignments
            .push(make_assignment_typed("done", 42, "api", Some("work")));
        // A running review assignment (headless, no tmux) is the liveness signal.
        let mut review = make_assignment_typed("running", 42, "api", Some("review"));
        review.is_interactive = false;
        app.data.assignments.push(review);

        assert!(app.live_tmux_sessions.is_empty());
        let groups = app.pipeline_active_by_liveness();
        assert_eq!(groups.len(), 1);
        assert_eq!(
            groups[0].0, "live",
            "running review assignment (non-work type) must render under Live"
        );
    }

    #[test]
    fn in_progress_no_running_assignment_stays_idle() {
        // An in-progress issue whose work assignment is done (not running)
        // and has no live tmux session must remain in Idle — we must not
        // false-positive on completed work.
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(make_assignment_typed("done", 42, "api", Some("work")));

        assert!(app.live_tmux_sessions.is_empty());
        let groups = app.pipeline_active_by_liveness();
        assert_eq!(groups.len(), 1);
        assert_eq!(
            groups[0].0, "idle",
            "issue with only a done assignment and no tmux session must stay Idle"
        );
    }

    #[test]
    fn review_stage_status_reflects_verdict_not_just_done() {
        // #473: the Review stage must key on review_verdict, not merely that the
        // review process ran (it always ends status="done").  A request-changes
        // verdict must NEVER render Done (green).
        let issue = PipelineIssue {
            number: 700,
            title: "x".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        };
        let mk_review = |verdict: Option<&str>| {
            let mut a = make_assignment_typed("done", 700, "api", Some("review"));
            a.review_verdict = verdict.map(|s| s.to_string());
            a.dispatched_at = Some(100.0); // no upstream → no #193 stale path
            a
        };
        let mut app = make_app_default();

        app.data.assignments = vec![mk_review(Some("approve"))];
        assert_eq!(app.stage_status_for(&issue, "review"), StageStatus::Done);

        app.data.assignments = vec![mk_review(Some("request-changes"))];
        assert_eq!(
            app.stage_status_for(&issue, "review"),
            StageStatus::Failed,
            "request-changes must render Failed (red), never green"
        );

        // #812: a terminal (status="done") review with no verdict must render
        // as Failed (red, recoverable), not Active (blue, permanently stuck).
        // In-flight reviews (status="running") are caught by the early
        // `any(status=="running") → Active` guard and never reach this arm.
        app.data.assignments = vec![mk_review(None)];
        let s = app.stage_status_for(&issue, "review");
        assert_ne!(s, StageStatus::Done, "a verdict-less review must not render green");
        assert_eq!(
            s,
            StageStatus::Failed,
            "#812: a done review with no verdict must render Failed (red/recoverable), not Active (blue/stuck)"
        );
    }

    #[test]
    fn review_stage_status_running_with_no_verdict_is_active_not_failed() {
        // #812 regression guard: in-flight reviews (status="running") must
        // still render Active (blue), NOT Failed — the absence of a verdict
        // during the session is expected.  Only a *terminal* (done) row with
        // no verdict is an error.
        let issue = PipelineIssue {
            number: 700,
            title: "x".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        };
        let mut a = make_assignment_typed("running", 700, "api", Some("review"));
        a.review_verdict = None;
        a.dispatched_at = Some(100.0);
        let mut app = make_app_default();
        app.data.assignments = vec![a];
        assert_eq!(
            app.stage_status_for(&issue, "review"),
            StageStatus::Active,
            "an in-flight review (running) with no verdict must still render Active"
        );
    }

