    // ── #245 / #329: force-merge confirm dialog ─────────────────────────────
    // The prompt is now a quadraui Dialog popup rather than a status-bar hint.

    #[test]
    fn pending_force_merge_dialog_shows_repo_scope() {
        // When pending_force_merge is Some(repo), build_prompt_dialog should
        // return a Dialog whose body mentions the --repo scope.
        let mut app = make_pipeline_app();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);
        app.pending_force_merge = Some("api".to_string());

        let dialog = app
            .build_prompt_dialog()
            .expect("expected a force-merge dialog");
        let body_text: String = dialog
            .body
            .iter()
            .flat_map(|b| b.spans.iter())
            .map(|s| s.text.as_str())
            .collect::<Vec<_>>()
            .join(" ");
        assert!(
            body_text.contains("--repo api"),
            "expected scoped scope in dialog body, got: {body_text}",
        );
        // Status bar still shows the normal Pipeline hint (dialog is the
        // affordance; status bar reverts to prior content).
        let bar = app.status_bar();
        let hint = bar
            .right_segments
            .iter()
            .map(|s| s.text.clone())
            .collect::<Vec<_>>()
            .join(" ");
        assert!(
            !hint.contains("Force-merge"),
            "force-merge hint should not be in status bar: {hint}"
        );
    }

    #[test]
    fn pending_force_merge_dialog_shows_whole_queue_when_no_repo() {
        // Empty repo string ⇒ scope line says "whole merge queue".
        let mut app = make_pipeline_app();
        app.pending_force_merge = Some(String::new());

        let dialog = app
            .build_prompt_dialog()
            .expect("expected a force-merge dialog");
        let body_text: String = dialog
            .body
            .iter()
            .flat_map(|b| b.spans.iter())
            .map(|s| s.text.as_str())
            .collect::<Vec<_>>()
            .join(" ");
        assert!(
            body_text.contains("whole merge queue"),
            "expected whole-queue scope in dialog body, got: {body_text}",
        );
    }

    #[test]
    fn pending_force_merge_dialog_not_in_status_bar() {
        // The force-merge confirm prompt must no longer bleed into the
        // status bar; the dialog is the sole affordance.  The status bar
        // should show the normal pipeline or board hint instead.
        let mut app = make_pipeline_app();
        app.active_view = SidebarView::Pipeline;
        app.pipeline_sel = Some(0);
        app.pending_force_merge = Some("api".to_string());
        let bar = app.status_bar();
        let hint = bar
            .right_segments
            .iter()
            .map(|s| s.text.clone())
            .collect::<Vec<_>>()
            .join(" ");
        assert!(
            !hint.contains("Force-merge"),
            "force-merge prompt leaked into status bar: {hint}"
        );
        assert!(
            !hint.contains("y=confirm"),
            "confirm key hint leaked into status bar: {hint}"
        );
        // A dialog should be buildable.
        assert!(
            app.build_prompt_dialog().is_some(),
            "expected dialog to be Some"
        );
    }

    #[test]
    fn status_bar_surfaces_live_interactive_sessions() {
        // #628: detached interactive sessions create no board `running` row, so
        // they were invisible and piled up. They must show as a persistent
        // status-bar badge whenever any are discovered.
        let mut app = make_test_app(BoardData::default());
        let left_text = |a: &CoordApp| {
            a.status_bar()
                .left_segments
                .iter()
                .map(|s| s.text.clone())
                .collect::<Vec<_>>()
                .join(" ")
        };

        // No sessions → no badge.
        assert!(
            !left_text(&app).contains("live session"),
            "no badge expected with zero sessions",
        );

        // Two live sessions → a badge with the count, regardless of board state.
        app.live_tmux_sessions = vec![
            LiveTmuxSession {
                assignment_id: "a".into(),
                issue_number: Some(1),
                repo_name: None,
                issue_title: None,
                machine: None,
                pane_dead: false,
            pending_sweep_count: 0,
            },
            LiveTmuxSession {
                assignment_id: "b".into(),
                issue_number: Some(2),
                repo_name: None,
                issue_title: None,
                machine: None,
                pane_dead: false,
            pending_sweep_count: 0,
            },
        ];
        assert!(
            left_text(&app).contains("2 live sessions"),
            "expected a '2 live sessions' badge, got: {}",
            left_text(&app),
        );

        // Singular form for one session.
        app.live_tmux_sessions.truncate(1);
        assert!(
            left_text(&app).contains("1 live session ")
                && !left_text(&app).contains("1 live sessions"),
            "expected singular '1 live session', got: {}",
            left_text(&app),
        );
    }

    #[test]
    fn live_session_count_for_machine_joins_sessions_to_assignments() {
        // #628 pt.2: the Machines tab counts live interactive sessions by
        // joining each session to its assignment's machine — independent of the
        // assignment's status, so a session whose work already merged (board row
        // → Done) is still counted while it stays live.
        let mut app = make_test_app(BoardData::default());
        let mut a1 = _stage_assignment("s1", "work", 100.0, "done"); // merged → Done
        a1.machine = "elitebook".to_string();
        let mut a2 = _stage_assignment("s2", "review", 100.0, "running");
        a2.machine = "dellserver".to_string();
        let mut a3 = _stage_assignment("s3", "fix", 100.0, "done");
        a3.machine = "dellserver".to_string();
        app.data.assignments = vec![a1, a2, a3];

        app.live_tmux_sessions = vec![
            LiveTmuxSession {
                assignment_id: "s1".into(),
                issue_number: None,
                repo_name: None,
                issue_title: None,
                machine: None,
                pane_dead: false,
            pending_sweep_count: 0,
            },
            LiveTmuxSession {
                assignment_id: "s2".into(),
                issue_number: None,
                repo_name: None,
                issue_title: None,
                machine: None,
                pane_dead: false,
            pending_sweep_count: 0,
            },
            LiveTmuxSession {
                assignment_id: "s3".into(),
                issue_number: None,
                repo_name: None,
                issue_title: None,
                machine: None,
                pane_dead: false,
            pending_sweep_count: 0,
            },
            // A session with no matching assignment can't be attributed → ignored.
            LiveTmuxSession {
                assignment_id: "ghost".into(),
                issue_number: None,
                repo_name: None,
                issue_title: None,
                machine: None,
                pane_dead: false,
            pending_sweep_count: 0,
            },
        ];

        assert_eq!(app.live_session_count_for_machine("elitebook"), 1);
        assert_eq!(app.live_session_count_for_machine("dellserver"), 2);
        assert_eq!(app.live_session_count_for_machine("precision"), 0);
    }

    // ── #628 Scope A: fleet-wide live-sessions overlay ─────────────────────

    #[test]
    fn live_sessions_overlay_opens_on_l_when_sessions_present() {
        // L opens the overlay when there are live sessions. We test via the
        // guard logic directly (same logic handle() checks) rather than calling
        // handle() which requires a real Backend.
        let mut app = make_test_app(BoardData::default());
        app.live_tmux_sessions = vec![LiveTmuxSession {
            assignment_id: "aid1".into(),
            issue_number: Some(10),
            repo_name: Some("api".into()),
            issue_title: None,
            machine: Some("elitebook".into()),
            pane_dead: false,
            pending_sweep_count: 0,
        }];
        assert!(app.live_sessions_overlay.is_none());
        // Simulate the L-toggle guard: sessions non-empty, no modal, no overlay.
        // This is the exact condition the L handler checks.
        let should_open = !app.live_tmux_sessions.is_empty()
            && app.issue_finder.is_none()
            && !app.any_blocking_modal_active()
            && app.live_sessions_overlay.is_none();
        assert!(should_open, "L guard must be true when sessions are present");
        if should_open {
            app.live_sessions_overlay = Some(LiveSessionsOverlay::default());
        }
        assert!(
            app.live_sessions_overlay.is_some(),
            "L must open the live-sessions overlay when sessions are present"
        );
    }

    #[test]
    fn live_sessions_overlay_does_not_open_when_no_sessions() {
        // L must be a no-op when there are no live sessions.
        let app = make_test_app(BoardData::default());
        assert!(app.live_tmux_sessions.is_empty());
        let should_open = !app.live_tmux_sessions.is_empty();
        assert!(
            !should_open,
            "L guard must be false when no sessions are present"
        );
        assert!(
            app.live_sessions_overlay.is_none(),
            "overlay must remain closed"
        );
    }

