    #[test]
    fn pipeline_loader_defaults_when_no_meta() {
        // Sanity: load_pipeline_meta returns documented defaults when the
        // DB is missing the keys (or the table is empty).
        let conn = Connection::open_in_memory().unwrap();
        conn.execute_batch("CREATE TABLE board_meta (key TEXT PRIMARY KEY, value TEXT);")
            .unwrap();
        let (gates, labels, repos, require_plan, run_cmds, repo_paths, _models) = load_pipeline_meta(&conn);
        assert_eq!(gates, vec!["review".to_string(), "merge".to_string()]);
        assert_eq!(labels, vec!["coord".to_string()]);
        assert!(repos.is_empty());
        assert!(!require_plan);
        assert!(run_cmds.is_empty(), "no run_cmds configured → empty map");
        assert!(
            repo_paths.is_empty(),
            "no repo_paths configured → empty map"
        );
    }

    #[test]
    fn pipeline_loader_reads_persisted_values() {
        let conn = Connection::open_in_memory().unwrap();
        conn.execute_batch(
            "CREATE TABLE board_meta (key TEXT PRIMARY KEY, value TEXT);
             INSERT INTO board_meta VALUES \
              ('pipeline_default_gates', '[\"plan\",\"work\",\"smoke\"]'), \
              ('pipeline_tracked_labels', '[\"hotfix\",\"feature\"]'), \
              ('pipeline_repos', '{\"api\":\"acme/api\"}'), \
              ('pipeline_repo_run_cmds', '{\"api\":\"cargo run --example gtk_panel\"}'), \
              ('pipeline_repo_paths', '{\"api\":\"/home/user/src/api\"}'), \
              ('pipeline_require_plan', '1');",
        )
        .unwrap();
        let (gates, labels, repos, require_plan, run_cmds, repo_paths, _models) = load_pipeline_meta(&conn);
        assert_eq!(gates, vec!["plan", "work", "smoke"]);
        assert_eq!(labels, vec!["hotfix", "feature"]);
        assert_eq!(repos, vec![("api".to_string(), "acme/api".to_string())]);
        assert!(require_plan);
        assert_eq!(
            run_cmds.get("api").map(|s| s.as_str()),
            Some("cargo run --example gtk_panel"),
            "run_cmds parsed from board_meta",
        );
        assert_eq!(
            repo_paths.get("api").map(|s| s.as_str()),
            Some("/home/user/src/api"),
            "repo_paths parsed from board_meta",
        );
    }

    // ── Purge helpers ─────────────────────────────────────────────────────────

    /// Build an in-memory DB with the columns the purge predicates read.
    /// Only the columns referenced by the SQL need to exist; this keeps the
    /// fixture small and decoupled from the production schema migrations.
    fn make_purge_db() -> Connection {
        let conn = Connection::open_in_memory().unwrap();
        conn.execute_batch(
            "CREATE TABLE assignments (
                assignment_id TEXT PRIMARY KEY,
                status TEXT NOT NULL,
                finished_at REAL
             );
             CREATE TABLE issues (
                number INTEGER PRIMARY KEY,
                state TEXT NOT NULL,
                synced_at REAL
             );",
        )
        .unwrap();
        conn
    }

    fn insert_assignment(conn: &Connection, id: &str, status: &str, finished_at: Option<f64>) {
        conn.execute(
            "INSERT INTO assignments (assignment_id, status, finished_at) VALUES (?1, ?2, ?3)",
            rusqlite::params![id, status, finished_at],
        )
        .unwrap();
    }

    fn insert_issue(conn: &Connection, number: i64, state: &str, synced_at: Option<f64>) {
        conn.execute(
            "INSERT INTO issues (number, state, synced_at) VALUES (?1, ?2, ?3)",
            rusqlite::params![number, state, synced_at],
        )
        .unwrap();
    }

    // ── count_purgeable_conn ──────────────────────────────────────────────────

    #[test]
    fn count_purgeable_counts_done_rows_older_than_cutoff() {
        let conn = make_purge_db();
        insert_assignment(&conn, "old", "done", Some(100.0)); // older than cutoff
        insert_assignment(&conn, "new", "done", Some(500.0)); // newer than cutoff
        let (a, i) = count_purgeable_conn(&conn, 300.0).unwrap();
        assert_eq!(a, 1);
        assert_eq!(i, 0);
    }

    #[test]
    fn count_purgeable_excludes_running_and_pending() {
        let conn = make_purge_db();
        insert_assignment(&conn, "r", "running", Some(0.0));
        insert_assignment(&conn, "p", "pending", Some(0.0));
        let (a, _) = count_purgeable_conn(&conn, 300.0).unwrap();
        assert_eq!(a, 0);
    }

    #[test]
    fn count_purgeable_includes_old_failed_rows() {
        let conn = make_purge_db();
        insert_assignment(&conn, "f", "failed", Some(100.0));
        let (a, _) = count_purgeable_conn(&conn, 300.0).unwrap();
        assert_eq!(a, 1);
    }

    #[test]
    fn count_purgeable_excludes_rows_with_no_finished_at() {
        let conn = make_purge_db();
        insert_assignment(&conn, "d", "done", None);
        let (a, _) = count_purgeable_conn(&conn, 300.0).unwrap();
        assert_eq!(a, 0);
    }

    #[test]
    fn count_purgeable_counts_closed_issues_older_than_cutoff() {
        let conn = make_purge_db();
        insert_issue(&conn, 1, "closed", Some(100.0)); // purgeable
        insert_issue(&conn, 2, "closed", Some(500.0)); // too fresh
        insert_issue(&conn, 3, "open", Some(50.0)); // open: never purged
        insert_issue(&conn, 4, "closed", None); // no synced_at: never purged
        let (_, i) = count_purgeable_conn(&conn, 300.0).unwrap();
        assert_eq!(i, 1);
    }

    // ── count vs delete symmetry ─────────────────────────────────────────────

    #[test]
    fn count_matches_delete_for_mixed_data() {
        // The reviewer's bug #2: prompt showed one number, toast showed another
        // because count_purgeable saw assignments-only and the SQL also deleted
        // issues. This test guards against future drift between the two helpers.
        let conn = make_purge_db();
        insert_assignment(&conn, "a1", "done", Some(100.0));
        insert_assignment(&conn, "a2", "failed", Some(100.0));
        insert_assignment(&conn, "a3", "done", Some(500.0)); // too fresh
        insert_issue(&conn, 1, "closed", Some(100.0));
        insert_issue(&conn, 2, "closed", Some(200.0));
        insert_issue(&conn, 3, "open", Some(100.0));

        let counted = count_purgeable_conn(&conn, 300.0).unwrap();
        let deleted = purge_done_assignments_conn(&conn, 300.0).unwrap();
        assert_eq!(counted, deleted, "count and delete must agree exactly");
        assert_eq!(counted, (2, 2));
    }

    // ── record_test_verdict_conn ──────────────────────────────────────────────

    /// Build an in-memory DB with the columns `record_test_verdict_conn` writes.
    fn make_verdict_db() -> Connection {
        let conn = Connection::open_in_memory().unwrap();
        conn.execute_batch(
            "CREATE TABLE assignments (
                assignment_id      TEXT PRIMARY KEY,
                test_state         TEXT,
                test_reason        TEXT,
                smoke_test         TEXT,
                smoke_test_reason  TEXT
             );",
        )
        .unwrap();
        conn
    }

    fn insert_verdict_row(conn: &Connection, id: &str) {
        conn.execute(
            "INSERT INTO assignments (assignment_id) VALUES (?1)",
            rusqlite::params![id],
        )
        .unwrap();
    }

    fn read_verdict(
        conn: &Connection,
        id: &str,
    ) -> (
        Option<String>,
        Option<String>,
        Option<String>,
        Option<String>,
    ) {
        conn.query_row(
            "SELECT test_state, test_reason, smoke_test, smoke_test_reason \
             FROM assignments WHERE assignment_id = ?1",
            rusqlite::params![id],
            |r| Ok((r.get(0)?, r.get(1)?, r.get(2)?, r.get(3)?)),
        )
        .unwrap()
    }

    #[test]
    // #296 Blocker 2: record_test_verdict_conn must mirror smoke_test so that
    // `coord fix` (which guards on smoke_test == "fail") can proceed after a
    // report+fix action from the TUI.
    fn record_test_verdict_conn_sets_smoke_test_on_failure() {
        let conn = make_verdict_db();
        insert_verdict_row(&conn, "w1");
        record_test_verdict_conn(&conn, "w1", "failed", Some("scroll broken")).unwrap();
        let (test_state, test_reason, smoke_test, smoke_reason) = read_verdict(&conn, "w1");
        assert_eq!(
            test_state.as_deref(),
            Some("failed"),
            "test_state must be 'failed'"
        );
        assert_eq!(
            test_reason.as_deref(),
            Some("scroll broken"),
            "test_reason must be stored"
        );
        assert_eq!(
            smoke_test.as_deref(),
            Some("fail"),
            "smoke_test must be mirrored to 'fail' so coord fix can dispatch",
        );
        assert_eq!(
            smoke_reason.as_deref(),
            Some("scroll broken"),
            "smoke_test_reason must match"
        );
    }

    #[test]
    fn record_test_verdict_conn_sets_smoke_test_pass_on_passed() {
        let conn = make_verdict_db();
        insert_verdict_row(&conn, "w2");
        record_test_verdict_conn(&conn, "w2", "passed", None).unwrap();
        let (test_state, _test_reason, smoke_test, smoke_reason) = read_verdict(&conn, "w2");
        assert_eq!(test_state.as_deref(), Some("passed"));
        assert_eq!(smoke_test.as_deref(), Some("pass"));
        assert_eq!(smoke_reason, None, "no smoke_test_reason for a pass");
    }

    #[test]
    fn record_test_verdict_conn_skipped_does_not_set_smoke_test() {
        let conn = make_verdict_db();
        insert_verdict_row(&conn, "w3");
        record_test_verdict_conn(&conn, "w3", "skipped", None).unwrap();
        let (test_state, _test_reason, smoke_test, _smoke_reason) = read_verdict(&conn, "w3");
        assert_eq!(test_state.as_deref(), Some("skipped"));
        assert_eq!(
            smoke_test, None,
            "smoke_test must not be set for skipped verdict"
        );
    }

    // ── board_selection_in_completed_group ────────────────────────────────────

    /// #265 helper: build an app where issue #10 is closed (on GitHub)
    /// and has a done assignment, so it lands in the Completed group.
    fn make_app_with_one_completed_issue() -> CoordApp {
        let mut app = make_app_with_assignments(vec![make_assignment_typed(
            "done",
            10,
            "repo-a",
            Some("work"),
        )]);
        app.data.open_issues.push(OpenIssue {
            repo_name: "repo-a".to_string(),
            number: 10,
            title: "closed one".to_string(),
            body: String::new(),
            state: "closed".to_string(),
            labels: Vec::new(),
            milestone_number: None,
            milestone_title: None,
        });
        app.rebuild_board_sidebar();
        app
    }

    #[test]
    fn purge_guard_true_when_completed_group_header_selected() {
        // #265 / #406: a "done" assignment on a *closed* GitHub issue lands
        // in the Completed group.
        // With the 3-level tree, the Completed status header is at path
        // [milestone_idx=0, status_idx=0] (the only non-empty group within
        // the "No milestone" milestone).
        let mut app = make_app_with_one_completed_issue();
        // Section 1 = repo-a (section 0 is the search form).
        app.board_sidebar.set_active_section(Some(1));
        // Path [0, 0]: milestone 0 ("No milestone"), status 0 ("Completed").
        app.board_sidebar.set_selected_path(1, Some(vec![0, 0]));
        assert!(app.board_selection_in_completed_group());
    }

    #[test]
    fn purge_guard_true_when_issue_row_in_completed_group_selected() {
        // Issue row within Completed group.
        // #406: path is now 3-level: [milestone_idx, status_idx, issue_idx].
        let mut app = make_app_with_one_completed_issue();
        app.board_sidebar.set_active_section(Some(1));
        app.board_sidebar.set_selected_path(1, Some(vec![0, 0, 0]));
        assert!(app.board_selection_in_completed_group());
    }

    #[test]
    fn purge_guard_false_when_running_group_selected() {
        // Running group only — group_idx 0 is "Running", not "Completed".
        let assignments = vec![make_assignment_typed("running", 10, "repo-a", Some("work"))];
        let mut app = make_app_with_assignments(assignments);
        app.board_sidebar.set_active_section(Some(1));
        app.board_sidebar.set_selected_path(1, Some(vec![0]));
        assert!(!app.board_selection_in_completed_group());
    }

    #[test]
    fn purge_guard_false_when_failed_group_selected() {
        let assignments = vec![make_assignment_typed("failed", 10, "repo-a", Some("work"))];
        let mut app = make_app_with_assignments(assignments);
        app.board_sidebar.set_active_section(Some(1));
        app.board_sidebar.set_selected_path(1, Some(vec![0]));
        assert!(!app.board_selection_in_completed_group());
    }

    #[test]
    fn purge_guard_false_when_no_section_active() {
        let app = make_app_default();
        assert!(!app.board_selection_in_completed_group());
    }

    // ── SSE watch overlay ────────────────────────────────────────────────────

    /// The canonical assignment id used by test watch contexts.
    const TEST_AID: &str = "test-id";

    /// Build a `WatchSseState` with a test sender and receiver pair.
    fn make_sse_state_pair() -> (WatchSseState, std::sync::mpsc::Sender<SseWatchMsg>) {
        let (tx, rx) = std::sync::mpsc::channel::<SseWatchMsg>();
        let state = WatchSseState {
            rx,
            lines: Vec::new(),
            last_event_id: 0,
            fail_count: 0,
            first_fail_at: None,
            done: false,
            host: "localhost".to_string(),
            pending_tail: String::new(),
            line_times: Vec::new(),
            current_turn: 0,
        };
        (state, tx)
    }

    /// Build a focused `WatchContext` in the app's pool.
    ///
    /// Sets `watch_focused` so all watch-overlay code paths (j/k scroll, chat
    /// opener, drain, etc.) behave as if the user pressed Enter on issue 42.
    fn install_watch_ctx(app: &mut CoordApp, sse: WatchSseState) {
        let aid = TEST_AID.to_string();
        let state = WatchState {
            assignment_id: aid.clone(),
            machine: "remote".to_string(),
            repo: "myrepo".to_string(),
            issue_number: 42,
            assignment_type: "work".to_string(),
            scroll: usize::MAX,
        };
        let ctx = WatchContext {
            state,
            sse,
            inject_transcript: Vec::new(),
            inject_sse_offsets: Vec::new(),
            history_turns: Vec::new(),
            last_focused_at: Instant::now(),
        };
        app.watch_pool.insert(aid.clone(), ctx);
        app.watch_focused = Some(aid);
    }

    #[test]
    fn drain_sse_watch_accumulates_lines() {
        let mut app = make_app_default();
        let (state, tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        // Each chunk's text has a trailing `\n` — that's what the agent
        // emits when the source bytes ended at a line boundary.
        tx.send(SseWatchMsg::Lines {
            last_id: 100,
            text: "line one\nline two\n".to_string(),
        })
        .unwrap();
        tx.send(SseWatchMsg::Lines {
            last_id: 200,
            text: "line three\n".to_string(),
        })
        .unwrap();

        let changed = app.drain_sse_watch();
        assert!(changed, "new lines should trigger redraw");

        let sse = &app.watch_pool[TEST_AID].sse;
        assert_eq!(sse.last_event_id, 200);
        assert_eq!(sse.lines, vec!["line one", "line two", "line three"]);
        assert!(!sse.done);
    }

    #[test]
    fn drain_sse_watch_reassembles_partial_line_split_across_chunks() {
        // Regression: the agent reads the log in 4 KB chunks, so a long JSON
        // line (e.g. `{"type":"result", ..., "total_cost_usd":...}`) arrives
        // in pieces. Without reassembly the broken halves reach the parser
        // and we lose fields after the split point — surfaced as $0.00 /
        // stop=? in the watch overlay.
        let mut app = make_app_default();
        let (state, tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        // Chunk 1 has the first half of a JSON line (NO trailing newline).
        tx.send(SseWatchMsg::Lines {
            last_id: 100,
            text: "{\"type\":\"result\",\"num_turns\":37".to_string(),
        })
        .unwrap();
        // Chunk 2 has the rest plus the terminating newline.
        tx.send(SseWatchMsg::Lines {
            last_id: 200,
            text: ",\"total_cost_usd\":1.75}\n".to_string(),
        })
        .unwrap();

        app.drain_sse_watch();

        let sse = &app.watch_pool[TEST_AID].sse;
        assert_eq!(sse.last_event_id, 200);
        assert_eq!(
            sse.lines,
            vec!["{\"type\":\"result\",\"num_turns\":37,\"total_cost_usd\":1.75}"],
            "the two chunks must have been joined into one line, not two"
        );
        assert!(
            sse.pending_tail.is_empty(),
            "tail should be flushed after the second chunk"
        );
    }

    #[test]
    fn drain_sse_watch_marks_done_on_end_event() {
        let mut app = make_app_default();
        let (state, tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        // Trailing `\n` so the chunk is complete (no partial line to flush).
        tx.send(SseWatchMsg::Lines {
            last_id: 50,
            text: "some output\n".to_string(),
        })
        .unwrap();
        tx.send(SseWatchMsg::Done { last_id: 99 }).unwrap();

        let changed = app.drain_sse_watch();
        assert!(changed);

        let sse = &app.watch_pool[TEST_AID].sse;
        assert!(sse.done, "done should be set after End event");
        assert_eq!(sse.last_event_id, 99);
        assert_eq!(sse.lines, vec!["some output"]);
    }

    #[test]
    fn drain_sse_watch_flushes_pending_tail_on_done() {
        // If the stream ends without the writer's final newline, the partial
        // line should still surface (don't silently drop the worker's last
        // result line).
        let mut app = make_app_default();
        let (state, tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        tx.send(SseWatchMsg::Lines {
            last_id: 10,
            text: "trailing partial".to_string(),
        })
        .unwrap();
        tx.send(SseWatchMsg::Done { last_id: 11 }).unwrap();

        app.drain_sse_watch();
        let sse = &app.watch_pool[TEST_AID].sse;
        assert!(sse.done);
        assert_eq!(sse.lines, vec!["trailing partial"]);
    }

    #[test]
    fn drain_sse_watch_heartbeat_is_silent() {
        let mut app = make_app_default();
        let (state, tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        // Only heartbeat — channel still live.
        tx.send(SseWatchMsg::Heartbeat).unwrap();
        // Drain; no new content should be reported.
        let _ = app.drain_sse_watch();

        let sse = &app.watch_pool[TEST_AID].sse;
        assert!(sse.lines.is_empty());
        assert!(!sse.done);
        assert_eq!(sse.fail_count, 0);
    }

    #[test]
    fn drain_sse_watch_reconnects_on_first_error() {
        let mut app = make_app_default();
        let (state, tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        // One error — should schedule reconnect but not set done.
        tx.send(SseWatchMsg::Error("connection refused".to_string()))
            .unwrap();
        let changed = app.drain_sse_watch();
        assert!(changed);

        let sse = &app.watch_pool[TEST_AID].sse;
        assert_eq!(sse.fail_count, 1);
        assert!(!sse.done, "one error should not permanently stop reconnect");
        // A pool entry should still exist (reconnect was attempted).
        assert!(app.watch_pool.contains_key(TEST_AID));
    }

    #[test]
    fn drain_sse_watch_error_keeps_lines_and_times_in_lockstep() {
        // #899 regression: the SSE-error arm surfaces a "[sse error]" line in
        // `sse.lines`. It MUST push a matching `sse.line_times` entry — the
        // render cache-extend path (render.rs) derives slice indices from
        // `lines.len()` and applies them to `line_times`, so any desync panics
        // ("range start index N out of range for slice of length 0"). Before
        // the fix this arm pushed to `lines` only, leaving line_times empty.
        let mut app = make_app_default();
        let (state, tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        tx.send(SseWatchMsg::Error("connection refused".to_string()))
            .unwrap();
        app.drain_sse_watch();

        let sse = &app.watch_pool[TEST_AID].sse;
        assert!(
            !sse.lines.is_empty(),
            "the [sse error] line should be surfaced in the log"
        );
        assert_eq!(
            sse.lines.len(),
            sse.line_times.len(),
            "lines/line_times must stay in lockstep after an SSE error (#899)"
        );
    }

    #[test]
    fn drain_sse_watch_stops_after_three_errors() {
        let mut app = make_app_default();
        let (state, _tx) = make_sse_state_pair(); // tx unused; rx gets replaced below
        install_watch_ctx(&mut app, state);

        // First two errors — manipulate fail_count directly.
        if let Some(ctx) = app.watch_pool.get_mut(TEST_AID) {
            ctx.sse.fail_count = 2;
            ctx.sse.first_fail_at = Some(Instant::now());
        }
        // Now fail_count = 2; send one more error to push it to 3.
        let (state2, tx2) = make_sse_state_pair();
        if let Some(ctx) = app.watch_pool.get_mut(TEST_AID) {
            ctx.sse.rx = state2.rx;
        }
        tx2.send(SseWatchMsg::Error("third failure".to_string()))
            .unwrap();

        let changed = app.drain_sse_watch();
        assert!(changed);

        let sse = &app.watch_pool[TEST_AID].sse;
        assert!(sse.done, "three errors should set done");
        assert_eq!(sse.fail_count, 3);
        // A toast should have been pushed.
        assert!(
            !app.toasts.is_empty(),
            "error toast should be pushed on fail limit"
        );
    }

    #[test]
    fn drain_sse_watch_noop_when_done() {
        let mut app = make_app_default();
        let (mut state, tx) = make_sse_state_pair();
        state.done = true;
        install_watch_ctx(&mut app, state);

        // Send lines — should be ignored because done=true.
        tx.send(SseWatchMsg::Lines {
            last_id: 10,
            text: "ignored".to_string(),
        })
        .unwrap();
        let changed = app.drain_sse_watch();
        assert!(!changed, "done state should not trigger redraw");
        assert!(app.watch_pool[TEST_AID].sse.lines.is_empty());
    }

    #[test]
    fn close_watch_clears_focus_but_keeps_pool() {
        // close_watch() should clear watch_focused (hiding the overlay) but
        // leave the pool entry alive so background accumulation continues.
        let mut app = make_app_default();
        let (state, _tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);
        assert!(
            app.watch_focused.is_some(),
            "should be focused after install"
        );

        app.close_watch();

        assert!(
            app.watch_focused.is_none(),
            "watch_focused should be cleared"
        );
        assert!(
            app.watch_pool.contains_key(TEST_AID),
            "pool entry should survive close_watch"
        );
    }

    #[test]
    fn close_watch_clears_inject_opened_from_log_tab_flag() {
        // #386: close_watch() must clear the inject_opened_from_log_tab
        // flag.  If it didn't, a stale `true` could survive into a later
        // chat session and trigger the Cancelled arm's `watch_focused = None`
        // restore on a context where the user did want watch_focused to
        // persist, breaking the Log-tab invariant (#308) in the other
        // direction.  The flag's lifetime is bounded by close_watch and by
        // the Cancelled arm itself.
        let mut app = make_app_default();
        app.inject_opened_from_log_tab = true;

        app.close_watch();

        assert!(
            !app.inject_opened_from_log_tab,
            "close_watch must clear inject_opened_from_log_tab (#386 invariant)",
        );
    }

    #[test]
    fn submit_inject_with_toast_false_suppresses_steer_toast() {
        // #386: refinement-notes synth (Ctrl+N) calls submit_inject_with_toast
        // with show_toast=false because it emits its own tailored toast.
        // Verify the "Steer sent" toast is NOT pushed on that path so the
        // user doesn't see a "Steer sent" confirmation for a button they
        // never pressed.
        let mut app = make_test_app(BoardData {
            machines: vec![Machine {
                name: "remote".to_string(),
                host: "tests-localhost".to_string(),
                reachable: true,
                active_count: 0,
                repos: vec![],
                version: None,
                worktree_bytes: 0,
            }],
            ..BoardData::default()
        });
        let (state, _tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        let toasts_before = app.toasts.len();
        let ok = app.submit_inject_with_toast("hello worker".to_string(), false);
        assert!(ok, "submit_inject should succeed on the live-worker path");

        let new_toasts: Vec<_> = app
            .toasts
            .iter()
            .skip(toasts_before)
            .map(|(item, _, _)| item.title.clone())
            .collect();
        assert!(
            !new_toasts.iter().any(|t| t == "Steer sent"),
            "show_toast=false must suppress 'Steer sent'; got toasts: {:?}",
            new_toasts,
        );
    }

    #[test]
    fn submit_inject_default_shows_steer_toast() {
        // Counterpart to the suppression test: the user-typed steer path
        // calls submit_inject() (default show_toast=true) and SHOULD see
        // the optimistic confirmation toast.
        let mut app = make_test_app(BoardData {
            machines: vec![Machine {
                name: "remote".to_string(),
                host: "tests-localhost".to_string(),
                reachable: true,
                active_count: 0,
                repos: vec![],
                version: None,
                worktree_bytes: 0,
            }],
            ..BoardData::default()
        });
        let (state, _tx) = make_sse_state_pair();
        install_watch_ctx(&mut app, state);

        let toasts_before = app.toasts.len();
        let ok = app.submit_inject("hello worker".to_string());
        assert!(ok, "submit_inject should succeed on the live-worker path");

        let new_toast_titles: Vec<_> = app
            .toasts
            .iter()
            .skip(toasts_before)
            .map(|(item, _, _)| item.title.clone())
            .collect();
        assert!(
            new_toast_titles.iter().any(|t| t == "Steer sent"),
            "user-typed steer must surface 'Steer sent'; got toasts: {:?}",
            new_toast_titles,
        );
    }

