    // ── #876: TuiDriver black-box — Summary tab sources from board layer ─────────

    /// #876: The Summary tab must show the Test FAILED verdict AND the
    /// `test_reason` text, sourced from the in-memory board (not GitHub
    /// comments).  This is the exact regression from #865: test_reason
    /// is board-only and was never visible before this fix.
    #[test]
    fn summary_tab_shows_test_failed_verdict_and_reason_from_board() {
        use quadraui::tui::testing::driver_with_shell;

        // Build a work assignment: done, test=failed, reason set.
        let work = Assignment {
            id: "w-42-fail".to_string(),
            repo: "api".to_string(),
            issue_number: 42,
            issue_title: "Add cool thing".to_string(),
            machine: "dellserver".to_string(),
            status: "done".to_string(),
            branch: Some("issue-42-work".to_string()),
            model: Some("sonnet".to_string()),
            dispatched_at: Some(1_000_000.0),
            finished_at: Some(1_001_200.0),
            exit_code: Some(0),
            assignment_type: Some("work".to_string()),
            test_state: Some("failed".to_string()),
            test_reason: Some("cargo test failed: 3 test failures".to_string()),
            review_verdict: None,
            review_state: None,
            review_of_assignment_id: None,
            cost_usd: Some(0.42),
            smoke_tests: None,
            review_findings: None,
            test_plan: None,
            test_plan_branch_head: None,
            input_tokens: 0,
            output_tokens: 0,
            cache_creation_tokens: 0,
            cache_read_tokens: 0,
            is_interactive: false,
            failure_reason: None,
            review_iteration: 0,
            pr_url: None,
        };

        let data = BoardData {
            pipeline_default_gates: vec![
                "test".to_string(),
                "review".to_string(),
                "merge".to_string(),
            ],
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            assignments: vec![work],
            ..BoardData::default()
        };
        let mut app = make_test_app(data);
        app.pipeline_issues = vec![PipelineIssue {
            number: 42,
            title: "Add cool thing".to_string(),
            body: String::new(),
            repo_slug: "acme/api".to_string(),
            coord_repo: Some("api".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:ready".to_string()],
            is_closed: false,
        }];
        app.rebuild_pipeline_sidebar(None);
        app.pipeline_sel = Some(0);
        app.active_view = SidebarView::Pipeline;
        app.pipeline_detail_tab = PipelineDetailTab::Summary;

        let driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);

        // The Summary tab must render the FAILED verdict badge.
        assert!(
            driver.screen_contains("Test ✗"),
            "Summary tab must show test=failed badge:\n{}",
            driver.screen(),
        );
        // The test_reason text must be visible — this is the #865 regression.
        assert!(
            driver.screen_contains("cargo test failed"),
            "Summary tab must show test_reason from board layer:\n{}",
            driver.screen(),
        );
    }

    // ── parse_issue_proposal (#316) ────────────────────────────────────────────

    /// Helper: build a stream-json text line as the worker emits.
    fn stream_text(s: &str) -> String {
        // Escape backslashes and quotes; preserve newlines as \n escapes.
        let escaped = s
            .replace('\\', "\\\\")
            .replace('"', "\\\"")
            .replace('\n', "\\n");
        format!(r#"{{"type":"text","text":"{}"}}"#, escaped)
    }

    #[test]
    fn parse_issue_proposal_single_block() {
        let payload = stream_text("TITLE: Add foo support\n---\nWhat\nDo the thing.\n");
        let (title, body) = parse_issue_proposal(&payload).expect("parses");
        assert_eq!(title, "Add foo support");
        assert!(body.contains("Do the thing."));
        assert!(body.starts_with("What"));
    }

    #[test]
    fn parse_issue_proposal_uses_last_title_block() {
        // Two proposals in the transcript — the last one is the real draft.
        // This guards against the previously-fixed bug where `rfind` picked
        // the last TITLE but `skip_while` sliced body from the first.
        let payload = stream_text(
            "TITLE: Old draft\n---\nOld body content\n\nTITLE: New shiny draft\n---\nNew body content\n",
        );
        let (title, body) = parse_issue_proposal(&payload).expect("parses");
        assert_eq!(title, "New shiny draft");
        assert!(
            body.contains("New body content"),
            "expected new body, got: {:?}",
            body,
        );
        assert!(
            !body.contains("Old body content"),
            "should NOT have leaked old body; got: {:?}",
            body,
        );
    }

    #[test]
    fn parse_issue_proposal_returns_none_when_no_separator() {
        let payload = stream_text("TITLE: A title\nbut no separator follows\n");
        assert!(parse_issue_proposal(&payload).is_none());
    }

    #[test]
    fn parse_issue_proposal_returns_none_when_no_title() {
        let payload = stream_text("Some chat\n---\nstuff\n");
        assert!(parse_issue_proposal(&payload).is_none());
    }

    // ── #337: chat-type assignments must not drag issues into In-flight ────────

    /// Repro for quadraui #294 / coord #337: an issue with 3 done
    /// refinement assignments and `status:ready` label was showing up as
    /// In-progress in the TUI.  It should land in the Refined bucket.
    #[test]
    fn chat_type_assignments_do_not_drag_issue_into_in_flight() {
        // Three done refinement assignments (the exact repro from #294).
        let mut app = make_test_app(BoardData {
            assignments: vec![
                make_assignment_typed("done", 294, "repo-a", Some("refinement")),
                make_assignment_typed("done", 294, "repo-a", Some("refinement")),
                make_assignment_typed("done", 294, "repo-a", Some("refinement")),
            ],
            ..BoardData::default()
        });
        // Open issue with status:ready label — should be Refined, not In-flight.
        app.data.open_issues.push(OpenIssue {
            repo_name: "repo-a".to_string(),
            number: 294,
            title: "refine me".to_string(),
            body: String::new(),
            state: "open".to_string(),
            labels: vec!["status:ready".to_string()],
            milestone_number: None,
            milestone_title: None,
        });
        app.rebuild_board_sidebar();
        let cache = app.board_issues_cache.clone();
        let groups = app.board_grouped_for_repo(&cache, "repo-a");
        let sections: Vec<&str> = groups.iter().map(|(k, _)| *k).collect();
        assert!(
            !sections.contains(&"in-flight"),
            "#337 regression: refinement-only issue must not appear in In-flight; got {:?}",
            sections,
        );
        assert!(
            sections.contains(&"backlog"),
            "#337/#628: a refinement-only + status:ready issue is Backlog (status:ready gates nothing); got {:?}",
            sections,
        );
    }

    /// Same fix, but verify `test-chat` and `new-issue-chat` are also
    /// excluded — they are the other chat types that should not trigger
    /// In-flight placement.
    #[test]
    fn test_chat_and_new_issue_chat_do_not_drag_issue_into_in_flight() {
        let mut app = make_test_app(BoardData {
            assignments: vec![
                make_assignment_typed("done", 1, "repo-a", Some("test-chat")),
                make_assignment_typed("done", 2, "repo-a", Some("new-issue-chat")),
            ],
            ..BoardData::default()
        });
        // Issue 1: test-chat only + status:ready → Backlog (#628).
        app.data.open_issues.push(OpenIssue {
            repo_name: "repo-a".to_string(),
            number: 1,
            title: "test-chat issue".to_string(),
            body: String::new(),
            state: "open".to_string(),
            labels: vec!["status:ready".to_string()],
            milestone_number: None,
            milestone_title: None,
        });
        // Issue 2: new-issue-chat only, no label → Backlog.
        app.data.open_issues.push(OpenIssue {
            repo_name: "repo-a".to_string(),
            number: 2,
            title: "new-issue-chat issue".to_string(),
            body: String::new(),
            state: "open".to_string(),
            labels: Vec::new(),
            milestone_number: None,
            milestone_title: None,
        });
        app.rebuild_board_sidebar();
        let cache = app.board_issues_cache.clone();
        let groups = app.board_grouped_for_repo(&cache, "repo-a");
        let by_key: std::collections::HashMap<&str, usize> =
            groups.iter().map(|(k, v)| (*k, v.len())).collect();
        assert!(
            !by_key.contains_key("in-flight"),
            "#337: chat-type assignments must not produce an In-flight section; got {:?}",
            by_key,
        );
        // #628: status:ready no longer splits a Refined bucket — both chat-only
        // issues are Backlog.
        assert_eq!(by_key.get("refined"), None, "no Refined bucket (#628)");
        assert_eq!(
            by_key.get("backlog"),
            Some(&2),
            "#337/#628: both chat-only issues → Backlog",
        );
    }

    /// Verify the `is_workable_type` helper covers the canonical workable
    /// types and rejects all chat/scoping types.
    #[test]
    fn is_workable_type_covers_all_canonical_types() {
        // workable
        assert!(is_workable_type("work"));
        assert!(is_workable_type("review"));
        assert!(is_workable_type("smoke"));
        assert!(is_workable_type("conflict-fix"));
        assert!(is_workable_type("fix-1"));
        assert!(is_workable_type("fix-42"));
        assert!(is_workable_type("fix-"));

        // not workable
        assert!(!is_workable_type("refinement"));
        assert!(!is_workable_type("test-chat"));
        assert!(!is_workable_type("new-issue-chat"));
        assert!(!is_workable_type("plan"));
        assert!(!is_workable_type("unknown-type"));
    }

    // ── #336: sanitize_branch ──────────────────────────────────────────────

    #[test]
    fn sanitize_branch_passthrough_clean() {
        assert_eq!(sanitize_branch("issue-305"), "issue-305");
        assert_eq!(sanitize_branch("feature_foo.bar"), "feature_foo.bar");
        assert_eq!(sanitize_branch("abc123"), "abc123");
    }

    #[test]
    fn sanitize_branch_replaces_slash_runs() {
        // feature/my-thing → feature-my-thing (single dash per run)
        assert_eq!(sanitize_branch("feature/my-thing"), "feature-my-thing");
        // Double slash → single dash
        assert_eq!(sanitize_branch("a//b"), "a-b");
    }

    #[test]
    fn sanitize_branch_strips_leading_trailing_dashes() {
        assert_eq!(sanitize_branch("/leading"), "leading");
        assert_eq!(sanitize_branch("trailing/"), "trailing");
        assert_eq!(sanitize_branch("/both/"), "both");
    }

    #[test]
    fn sanitize_branch_matches_python_examples() {
        // issue-305-artifact-pull-rsync-built-binaries-from → unchanged (all allowed)
        let branch = "issue-305-artifact-pull-rsync-built-binaries-from";
        assert_eq!(sanitize_branch(branch), branch);
        // A branch with spaces (unusual but handled)
        assert_eq!(sanitize_branch("my branch name"), "my-branch-name");
        // refs/heads/<name> — two slashes → two dashes collapsed to one each.
        // Pinned against Python's `_sanitize_branch("refs/heads/main") == "refs-heads-main"`
        // so the agent stash path and TUI manifest lookup always agree.
        assert_eq!(sanitize_branch("refs/heads/main"), "refs-heads-main");
    }

