    #[test]
    #[cfg(unix)]
    fn terminal_tab_has_live_session_guards_quit() {
        // Regression: an unfocused Esc/q must not quit the app while an
        // interactive session is live in the Terminal tab.  This helper is the
        // guard; assert its three conditions (view, tab, live session).
        let mut app = make_app_default();
        let issue_key = ("o/r".to_string(), 99u64);
        app.pipeline_issues = vec![PipelineIssue {
            number: 99,
            title: "t".to_string(),
            body: String::new(),
            repo_slug: "o/r".to_string(),
            coord_repo: None,
            matched_labels: vec![],
            all_labels: vec![],
            is_closed: false,
        }];
        app.pipeline_sel = Some(0);
        app.active_view = SidebarView::Pipeline;
        app.pipeline_detail_tab = PipelineDetailTab::Terminal;

        // Terminal tab, but no session yet → quit NOT guarded.
        assert!(
            !app.terminal_tab_has_live_session(),
            "no session → guard false (quit allowed)"
        );

        // Spawn a live shell for the selected issue.
        let cwd = std::env::temp_dir();
        let sess =
            quadraui::terminal_engine::TerminalSession::spawn(80, 24, "/bin/sh", &cwd, 100)
                .expect("spawn /bin/sh");
        app.detail_terminal_sessions.insert(issue_key, sess);
        assert!(
            app.terminal_tab_has_live_session(),
            "live session on the Terminal tab → guard true (quit suppressed)"
        );

        // Leaving the Pipeline view → guard false (quit allowed again).
        app.active_view = SidebarView::Board;
        assert!(
            !app.terminal_tab_has_live_session(),
            "non-Pipeline view → guard false even with a live session"
        );
    }

    #[test]
    fn detail_terminal_lifecycle_cleanup_removes_stale_sessions() {
        // When pipeline_issues is refreshed and an issue is gone, its session
        // entry must be pruned so we don't keep orphaned PTYs.
        let mut app = make_app_default();
        // Pretend issue #1 has an active session (use a marker in the error
        // map since we can't easily inject a real TerminalSession here).
        // Keys are (repo_slug, number) per #455.
        app.detail_terminal_spawn_errors.insert(("o/r".to_string(), 1), "test-error".to_string());
        app.detail_terminal_spawn_errors.insert(("o/r".to_string(), 2), "test-error-2".to_string());

        // Simulate a pipeline refresh that drops issue #1 but keeps #2.
        let new_issues = vec![PipelineIssue {
            number: 2,
            title: "kept issue".to_string(),
            body: String::new(),
            repo_slug: "o/r".to_string(),
            coord_repo: None,
            matched_labels: vec![],
            all_labels: vec![],
            is_closed: false,
        }];
        // Apply the same logic that poll_pipeline_loader uses (open_issues is empty
        // in this app so live_keys is pipeline-only — the Board extension adds nothing,
        // correctly leaving stale-pipeline sessions to be pruned).
        app.pipeline_issues = new_issues;
        let mut live_keys: std::collections::HashSet<(String, u64)> =
            app.pipeline_issues.iter().map(|i| (i.repo_slug.clone(), i.number)).collect();
        for oi in &app.data.open_issues {
            let slug = app
                .data
                .pipeline_repos
                .iter()
                .find(|(name, _)| name == &oi.repo_name)
                .map(|(_, s)| s.clone())
                .unwrap_or_else(|| oi.repo_name.clone());
            live_keys.insert((slug, oi.number));
        }
        app.detail_terminal_sessions.retain(|k, _| live_keys.contains(k));
        app.detail_terminal_spawn_errors.retain(|k, _| live_keys.contains(k));

        // Issue #1 should have been pruned; issue #2 should remain.
        assert!(
            !app.detail_terminal_spawn_errors.contains_key(&("o/r".to_string(), 1)),
            "stale session for #1 should be pruned"
        );
        assert!(
            app.detail_terminal_spawn_errors.contains_key(&("o/r".to_string(), 2)),
            "kept session for #2 should remain"
        );
    }

    /// Helper: build live_keys using the same logic as apply_pending_data (after
    /// the board_issues_cache fix) and run the retain on `detail_terminal_spawn_errors`.
    fn run_board_retain_logic(app: &mut CoordApp) {
        // Rebuild board_issues_cache from current data (mirrors apply_pending_data).
        app.rebuild_board_sidebar();

        let mut live_keys: std::collections::HashSet<(String, u64)> =
            app.pipeline_issues.iter().map(|i| (i.repo_slug.clone(), i.number)).collect();

        // New logic: iterate board_issues_cache (covers open_issues AND
        // assignment-only Board entries — the fix for the d3dcd39 follow-up).
        for (repo, groups) in &app.board_issues_cache {
            let slug = app
                .data
                .pipeline_repos
                .iter()
                .find(|(name, _)| name.as_str() == repo.as_str())
                .map(|(_, s)| s.clone())
                .unwrap_or_else(|| repo.clone());
            for group in groups {
                live_keys.insert((slug.clone(), group.issue_number));
            }
        }
        let prune = !live_keys.is_empty() || app.detail_terminal_spawn_errors.is_empty();
        if prune {
            app.detail_terminal_spawn_errors.retain(|k, _| live_keys.contains(k));
        }
    }

    /// #675: Board-only terminal sessions (issue in open_issues, no status:*
    /// label) must NOT be pruned by the pipeline data tick.
    #[test]
    fn board_terminal_session_not_pruned_by_data_tick() {
        let mut app = make_test_app(BoardData {
            pipeline_repos: vec![("myrepo".to_string(), "owner/myrepo".to_string())],
            ..BoardData::default()
        });

        // A Board-only issue (no status:* label, so absent from pipeline_issues).
        // The detail-terminal key uses the slug: ("owner/myrepo", 42).
        let board_key = ("owner/myrepo".to_string(), 42u64);
        app.data.open_issues.push(OpenIssue {
            repo_name: "myrepo".to_string(),
            number: 42,
            title: "board-only issue".to_string(),
            body: String::new(),
            state: "open".to_string(),
            labels: vec![], // no status:* → NOT in pipeline
            milestone_number: None,
            milestone_title: None,
        });

        // A completely-gone issue (#99) — no longer in pipeline OR open_issues.
        let stale_key = ("owner/myrepo".to_string(), 99u64);

        // Seed spawn-error map to stand in for real TerminalSessions.
        app.detail_terminal_spawn_errors.insert(board_key.clone(), "board-chat".to_string());
        app.detail_terminal_spawn_errors.insert(stale_key.clone(), "stale".to_string());

        // pipeline_issues is empty — the Board issue was never dispatched to Pipeline.
        app.pipeline_issues = vec![];

        run_board_retain_logic(&mut app);

        assert!(
            app.detail_terminal_spawn_errors.contains_key(&board_key),
            "Board-only session (in open_issues) must survive the prune"
        );
        assert!(
            !app.detail_terminal_spawn_errors.contains_key(&stale_key),
            "Stale session (gone from both pipeline and board) must be pruned"
        );
    }

    /// #675 follow-up: Board issues visible ONLY from assignment records (no
    /// open_issues entry — coord sync hasn't run yet, or `coord assign` was
    /// used directly before the first sync) must also keep their terminal
    /// sessions across data ticks.  The d3dcd39 fix iterated open_issues only
    /// and missed this case; the board_issues_cache fix covers it.
    #[test]
    fn board_terminal_session_from_assignment_not_pruned() {
        let mut app = make_test_app(BoardData {
            pipeline_repos: vec![("myrepo".to_string(), "owner/myrepo".to_string())],
            ..BoardData::default()
        });

        // Issue #55 is visible on the Board ONLY because of an assignment —
        // coord sync hasn't been run so the issues table (open_issues) is EMPTY.
        let board_key = ("owner/myrepo".to_string(), 55u64);
        app.data.assignments.push(make_assignment_typed(
            "running",
            55,
            "myrepo",
            Some("chat"),
        ));
        // Confirm open_issues has no entry for this issue.
        assert!(
            app.data.open_issues.is_empty(),
            "test requires open_issues to be empty (assignment-only scenario)"
        );

        // Another pipeline issue with "coord" label — ensures live_keys is
        // non-empty so the prune guard fires and the retain runs.
        app.pipeline_issues = vec![PipelineIssue {
            number: 100,
            title: "pipeline issue".to_string(),
            body: String::new(),
            repo_slug: "owner/myrepo".to_string(),
            coord_repo: Some("myrepo".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: false,
        }];

        // A stale session for an issue no longer on board or pipeline.
        let stale_key = ("owner/myrepo".to_string(), 999u64);

        app.detail_terminal_spawn_errors.insert(board_key.clone(), "board-chat".to_string());
        app.detail_terminal_spawn_errors.insert(stale_key.clone(), "stale".to_string());

        run_board_retain_logic(&mut app);

        assert!(
            app.detail_terminal_spawn_errors.contains_key(&board_key),
            "Assignment-only Board session must survive (was absent from open_issues)"
        );
        assert!(
            !app.detail_terminal_spawn_errors.contains_key(&stale_key),
            "Stale session (no pipeline entry, no board entry) must be pruned"
        );
    }

    /// #455: same issue number in two different repos must get independent
    /// session / error slots — no collision.
    #[test]
    fn detail_terminal_sessions_keyed_by_repo_and_number() {
        let mut app = make_app_default();

        // Two repos, both happen to have an issue #336.
        let key_a = ("quadraui/quadraui".to_string(), 336u64);
        let key_b = ("JDonaghy/claude-coordinator".to_string(), 336u64);

        app.detail_terminal_spawn_errors.insert(key_a.clone(), "err-a".to_string());
        app.detail_terminal_spawn_errors.insert(key_b.clone(), "err-b".to_string());

        // Both entries must coexist independently.
        assert_eq!(
            app.detail_terminal_spawn_errors.get(&key_a).map(String::as_str),
            Some("err-a"),
            "quadraui #336 slot should hold err-a"
        );
        assert_eq!(
            app.detail_terminal_spawn_errors.get(&key_b).map(String::as_str),
            Some("err-b"),
            "coordinator #336 slot should hold err-b"
        );
        assert_eq!(app.detail_terminal_spawn_errors.len(), 2, "must have two distinct entries");

        // selected_issue_key() returns the right composite key when on Pipeline.
        // #675 BUG 3 fix: must be on Pipeline view — Board view uses the board
        // selection, not pipeline_sel.
        app.active_view = SidebarView::Pipeline;
        app.pipeline_issues = vec![
            PipelineIssue {
                number: 336,
                title: "quadraui issue".to_string(),
                body: String::new(),
                repo_slug: "quadraui/quadraui".to_string(),
                coord_repo: None,
                matched_labels: vec![],
                all_labels: vec![],
                is_closed: false,
            },
            PipelineIssue {
                number: 336,
                title: "coord issue".to_string(),
                body: String::new(),
                repo_slug: "JDonaghy/claude-coordinator".to_string(),
                coord_repo: None,
                matched_labels: vec![],
                all_labels: vec![],
                is_closed: false,
            },
        ];
        app.pipeline_sel = Some(0);
        assert_eq!(
            app.selected_issue_key(),
            Some(("quadraui/quadraui".to_string(), 336)),
            "selected_issue_key must include repo slug"
        );
        app.pipeline_sel = Some(1);
        assert_eq!(
            app.selected_issue_key(),
            Some(("JDonaghy/claude-coordinator".to_string(), 336)),
            "different repo with same number gives different key"
        );
    }

