    /// host_sel_update is a no-op when terminal_host_sel_dragging is false.
    #[test]
    #[cfg(unix)]
    fn host_sel_update_noop_when_not_dragging() {
        let mut app = make_terminal_app_with_session();
        // Start a selection then end it (dragging flag = false).
        app.terminal_host_sel_begin(1, 1);
        app.terminal_host_sel_update(5, 5);
        app.terminal_host_sel_end();
        // Now the selection is non-collapsed (1,1)→(5,5) with dragging=false.
        // Calling update should be a no-op: the end must not move.
        app.terminal_host_sel_update(9, 9);
        let sel = app
            .terminal_session
            .as_ref()
            .unwrap()
            .selection
            .as_ref()
            .expect("selection should still exist");
        assert_eq!((sel.end_col, sel.end_row), (5, 5), "update was a no-op");
    }

    // ── #790: F9 terminal copy mode ─────────────────────────────────────────
    //
    // Shift+drag can't reach coord-tui when it runs inside an outer tmux
    // (tmux consumes Shift for its own cross-pane selection), so a keyboard
    // toggle (F9) is the tmux-proof way to enter a host-side selection mode.
    // While copy mode is on, `terminal_should_host_select` forces a plain
    // left-drag onto the host-selection path instead of the PTY.

    /// The host-select decision includes copy mode: with mouse reporting ON
    /// and no Shift, a press normally forwards to the PTY (false) — but copy
    /// mode forces a host selection (true).
    #[test]
    fn copy_mode_forces_host_select_decision() {
        let mut app = make_test_app(BoardData::default());
        app.active_view = SidebarView::Terminal;
        // Baseline: reporting ON, no Shift, copy mode OFF → forward to PTY.
        assert!(
            !app.terminal_should_host_select(false, true),
            "reporting on + no shift + no copy mode → PTY, not host-select"
        );
        // Shift still forces host-select (classic override).
        assert!(app.terminal_should_host_select(true, true));
        // Reporting OFF always host-selects (plain shell).
        assert!(app.terminal_should_host_select(false, false));
        // Copy mode forces host-select even with reporting ON and no Shift —
        // the tmux-proof path.
        app.terminal_copy_mode = true;
        assert!(
            app.terminal_should_host_select(false, true),
            "copy mode must force host-select with reporting on and no shift"
        );
    }

    /// Copy mode is only available in the copy-capable terminal contexts:
    /// the standalone Terminal view and the Pipeline detail Terminal tab.
    /// The Board Terminal tab is Chat-scoped (#675) with no selection path.
    #[test]
    fn copy_mode_availability_by_view() {
        let mut app = make_test_app(BoardData::default());

        app.active_view = SidebarView::Terminal;
        assert!(app.terminal_copy_mode_available(), "Terminal view: available");

        app.active_view = SidebarView::Pipeline;
        app.pipeline_detail_tab = PipelineDetailTab::Terminal;
        assert!(
            app.terminal_copy_mode_available(),
            "Pipeline Terminal tab: available"
        );
        app.pipeline_detail_tab = PipelineDetailTab::Pipeline;
        assert!(
            !app.terminal_copy_mode_available(),
            "Pipeline non-Terminal tab: unavailable"
        );

        app.active_view = SidebarView::Board;
        app.board_detail_tab = BoardDetailTab::Terminal;
        assert!(
            !app.terminal_copy_mode_available(),
            "Board Terminal tab is Chat-scoped (#675) — copy mode unavailable"
        );
    }

    /// `exit_terminal_copy_mode` clears the flag, the drag flag, and any
    /// in-progress (uncopied) selection.
    #[test]
    #[cfg(unix)]
    fn exit_copy_mode_clears_all_state() {
        use quadraui::terminal_engine::TerminalSelection;
        let mut app = make_terminal_app_with_session();
        app.terminal_copy_mode = true;
        app.terminal_host_sel_dragging = true;
        app.terminal_session.as_mut().unwrap().selection = Some(TerminalSelection {
            start_row: 0,
            start_col: 0,
            end_row: 0,
            end_col: 5,
        });
        app.exit_terminal_copy_mode();
        assert!(!app.terminal_copy_mode, "copy mode cleared");
        assert!(!app.terminal_host_sel_dragging, "drag flag cleared");
        assert!(
            app.terminal_session.as_ref().unwrap().selection.is_none(),
            "uncopied selection discarded"
        );
    }

    /// A stale copy mode is dropped once the active view is no longer a
    /// copy-capable terminal context.  Mirrors the guard at the top of
    /// `dispatch_handle` (which cannot be driven headlessly because the
    /// shell-adapter driver hides the concrete `CoordApp` fields).
    #[test]
    fn stale_copy_mode_dropped_when_view_not_copy_capable() {
        let mut app = make_test_app(BoardData::default());
        app.terminal_copy_mode = true;
        // Move to a view where copy mode is not available.
        app.active_view = SidebarView::Board;
        app.board_detail_tab = BoardDetailTab::Terminal;
        assert!(!app.terminal_copy_mode_available());
        // The dispatch guard runs exactly this on every event.
        if app.terminal_copy_mode && !app.terminal_copy_mode_available() {
            app.exit_terminal_copy_mode();
        }
        assert!(
            !app.terminal_copy_mode,
            "copy mode must be cleared once the view is no longer copy-capable"
        );
    }

    /// Black-box: F9 toggles copy mode and the terminal pane's hint strip
    /// switches between the discoverability hint and the in-mode banner.
    /// Drives the full `event → handle → render` path against the headless
    /// backend and asserts on the rendered screen (the hint text is the
    /// user-visible proxy for `terminal_copy_mode`, which the shell-adapter
    /// driver hides).
    #[test]
    #[cfg(unix)]
    fn f9_toggles_copy_mode_and_updates_hint() {
        use quadraui::tui::testing::driver_with_shell;
        let app = make_terminal_app_with_session();
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);

        // Copy mode OFF: discoverability hint present, no in-mode banner.
        assert!(
            driver.screen_contains("F9 copy-mode"),
            "OFF: discoverability hint must be visible:\n{}",
            driver.screen()
        );
        assert!(
            !driver.screen_contains("COPY MODE"),
            "OFF: in-mode banner must be absent:\n{}",
            driver.screen()
        );

        // Press F9 → copy mode ON: banner replaces the hint.
        driver.press_named(quadraui::NamedKey::F(9));
        assert!(
            driver.screen_contains("COPY MODE"),
            "ON: in-mode banner must be visible:\n{}",
            driver.screen()
        );
        assert!(
            !driver.screen_contains("F9 copy-mode"),
            "ON: discoverability hint must be replaced by the banner:\n{}",
            driver.screen()
        );

        // Press F9 again → back OFF: hint restored.
        driver.press_named(quadraui::NamedKey::F(9));
        assert!(
            driver.screen_contains("F9 copy-mode"),
            "OFF again: discoverability hint restored:\n{}",
            driver.screen()
        );
        assert!(
            !driver.screen_contains("COPY MODE"),
            "OFF again: banner gone:\n{}",
            driver.screen()
        );
    }

    /// Black-box: Esc leaves copy mode (banner → hint) without copying.
    #[test]
    #[cfg(unix)]
    fn esc_exits_copy_mode_via_driver() {
        use quadraui::tui::testing::driver_with_shell;
        let mut app = make_terminal_app_with_session();
        app.terminal_copy_mode = true;
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        assert!(
            driver.screen_contains("COPY MODE"),
            "precondition: copy-mode banner visible:\n{}",
            driver.screen()
        );
        driver.press_named(quadraui::NamedKey::Escape);
        assert!(
            driver.screen_contains("F9 copy-mode") && !driver.screen_contains("COPY MODE"),
            "Esc must leave copy mode (hint restored):\n{}",
            driver.screen()
        );
    }

    /// Black-box: Ctrl+C copies the active selection AND exits copy mode so
    /// normal PTY mouse forwarding resumes (banner → hint).
    #[test]
    #[cfg(unix)]
    fn ctrl_c_in_copy_mode_copies_and_exits() {
        use quadraui::terminal_engine::TerminalSelection;
        use quadraui::tui::testing::driver_with_shell;
        let mut app = make_terminal_app_with_session();
        app.terminal_copy_mode = true;
        // A set selection makes `selected_text` return Some(_) (even over
        // blank cells), so the Ctrl+C copy path fires deterministically.
        app.terminal_session.as_mut().unwrap().selection = Some(TerminalSelection {
            start_row: 0,
            start_col: 0,
            end_row: 0,
            end_col: 5,
        });
        let mut driver = driver_with_shell(app, CoordApp::shell_config(), 120, 40);
        assert!(
            driver.screen_contains("COPY MODE"),
            "precondition: copy-mode banner visible:\n{}",
            driver.screen()
        );
        driver.ctrl_char('c');
        assert!(
            driver.screen_contains("F9 copy-mode") && !driver.screen_contains("COPY MODE"),
            "a copy must end copy mode (hint restored):\n{}",
            driver.screen()
        );
    }

    /// Direct-state check the shell-adapter driver can't reach: a copy through
    /// the Ctrl+C handler clears the session selection.  Confirms the
    /// selection is copyable (`Some(_)`) before the copy fires.
    #[test]
    #[cfg(unix)]
    fn selection_yields_copyable_text_for_ctrl_c() {
        use quadraui::terminal_engine::TerminalSelection;
        let mut app = make_terminal_app_with_session();
        app.terminal_session.as_mut().unwrap().selection = Some(TerminalSelection {
            start_row: 0,
            start_col: 0,
            end_row: 0,
            end_col: 5,
        });
        assert!(
            app.active_terminal_selected_text().is_some(),
            "a set selection yields Some(text) — the Ctrl+C copy path will fire"
        );
    }

    // ── #467: local `coord assign --interactive` launcher ────────────────────
    //
    // Replaces the #446 ssh+tmux launcher tests (deleted with the launcher
    // itself).  The Pipeline detail Terminal tab now auto-runs
    // `coord assign --interactive --repo <repo> <N>` in the embedded PTY;
    // the session is strictly human-attended.

    #[test]
    fn build_interactive_launch_cmd_is_exact_local_string() {
        // Pin the exact rendered line — the TUI's job is to construct this
        // string verbatim so the local `coord` CLI runs the human-attended
        // interactive launcher.
        let cmd = build_interactive_launch_cmd(
            None,
            "elitebook",
            "claude-coordinator",
            467,
            InteractiveLaunchMode::Work,
            None,
        );
        assert_eq!(
            cmd,
            "coord assign --interactive --no-plan elitebook claude-coordinator 467\r",
        );
    }

    #[test]
    fn build_interactive_launch_cmd_injects_config_path() {
        // The embedded terminal's cwd is the issue's repo, so the launcher must
        // pass --config so `coord` finds coordinator.yml (#467).
        let cmd = build_interactive_launch_cmd(
            Some("/home/john/src/claude-coordinator/coordinator.yml"),
            "elitebook",
            "claude-coordinator",
            467,
            InteractiveLaunchMode::Work,
            None,
        );
        assert_eq!(
            cmd,
            "coord assign --config /home/john/src/claude-coordinator/coordinator.yml --interactive --no-plan elitebook claude-coordinator 467\r",
        );
    }

    #[test]
    fn build_interactive_launch_cmd_ends_with_cr_to_auto_run() {
        // Trailing \r submits the launcher line so the PTY actually runs
        // it without a manual Enter.  Without this the line just sits in
        // the shell input buffer.
        let cmd =
            build_interactive_launch_cmd(None, "m", "anything", 1, InteractiveLaunchMode::Work, None);
        assert!(
            cmd.ends_with('\r'),
            "launcher must end with \\r; got: {cmd:?}"
        );
        // No double-Enter — only ONE \r at the end.
        assert_eq!(
            cmd.matches('\r').count(),
            1,
            "launcher must contain exactly one \\r (auto-run, not auto-submit-twice)",
        );
        // No stray \n either — the briefing is delivered by
        // `coord assign --interactive` itself, not by us.
        assert!(!cmd.contains('\n'), "launcher must not embed newlines");
    }

    #[test]
    fn build_troubleshoot_launch_cmd_is_single_line_file_briefing_and_read_only() {
        // #569 bugs #2 and #3: Troubleshoot must launch as a single physical
        // line with the briefing passed BY FILE (not inlined) and via the
        // read-only --troubleshoot mode (not a claim-gated work dispatch).
        let cmd = build_briefed_interactive_launch_cmd(
            "--troubleshoot",
            None,
            "/tmp/coord-troubleshoot-42.md",
            "elitebook",
            "claude-coordinator",
            42,
        );
        // Bug #2: ONE physical line — the trailing \r is the submit key, not a
        // line break.  A multi-line briefing inlined here would split on its
        // newlines and strand the PTY shell at `quote>`.
        assert_eq!(cmd.matches('\r').count(), 1, "exactly one \\r: {cmd:?}");
        assert!(
            !cmd.trim_end_matches('\r').contains('\n'),
            "troubleshoot launch must be a single line: {cmd:?}"
        );
        // Bug #2: briefing delivered by file, not inlined.
        assert!(
            cmd.contains("--briefing-file /tmp/coord-troubleshoot-42.md"),
            "must pass --briefing-file: {cmd}"
        );
        // Bug #3: read-only --troubleshoot mode, NOT a claim-gated work dispatch.
        assert!(cmd.contains("--interactive --troubleshoot"), "{cmd}");
        assert!(
            !cmd.contains("--no-plan"),
            "must not use the old claim-gated work dispatch: {cmd}"
        );
        assert!(cmd.contains("claude-coordinator"), "{cmd}");
        assert!(cmd.ends_with("42\r"), "issue number at the tail: {cmd:?}");
    }

    #[test]
    fn build_interactive_launch_cmd_invokes_coord_assign_interactive() {
        // The launcher MUST route through the existing
        // `coord assign --interactive` path so the briefing seed is
        // bracketed-paste-delivered by interactive.py rather than
        // ad-hoc-injected by the TUI.
        let cmd = build_interactive_launch_cmd(
            None,
            "elitebook",
            "claude-coordinator",
            467,
            InteractiveLaunchMode::Work,
            None,
        );
        assert!(
            cmd.starts_with("coord assign --interactive "),
            "must invoke `coord assign --interactive`; got: {cmd:?}",
        );
        assert!(
            cmd.contains("elitebook claude-coordinator 467"),
            "must pass positional machine/repo/issue; got: {cmd:?}",
        );
        // Issue number trails the flags as a positional argument.
        assert!(
            cmd.contains(" 467\r"),
            "must end with ` <issue>\\r`; got: {cmd:?}",
        );
        // No ssh, no tmux, no clipboard — the abandoned remote path is
        // gone (#446 → #467).
        assert!(!cmd.contains("ssh "), "must not invoke ssh");
        assert!(!cmd.contains("tmux"), "must not invoke tmux");
    }

    #[test]
    fn build_interactive_launch_cmd_templates_repo_and_issue() {
        // Same shape, different repo + issue → both fields propagate.
        let cmd =
            build_interactive_launch_cmd(None, "m", "quadraui", 99, InteractiveLaunchMode::Work, None);
        assert_eq!(cmd, "coord assign --interactive --no-plan m quadraui 99\r");
        let cmd2 =
            build_interactive_launch_cmd(None, "m", "coord-tui", 1234, InteractiveLaunchMode::Work, None);
        assert_eq!(
            cmd2,
            "coord assign --interactive --no-plan m coord-tui 1234\r"
        );
    }

    #[test]
    fn build_interactive_launch_cmd_plan_mode_seeds_plan_then_work_briefing() {
        // #467: Plan mode forces work tools (--no-plan) AND seeds a plan-first
        // briefing via --briefing, so the session plans then implements in one
        // session.
        let cmd = build_interactive_launch_cmd(
            None,
            "elitebook",
            "claude-coordinator",
            467,
            InteractiveLaunchMode::Plan,
            None,
        );
        assert!(
            cmd.starts_with("coord assign --interactive --no-plan --briefing "),
            "plan mode must force work tools and pass a briefing; got: {cmd:?}",
        );
        assert!(
            cmd.contains(" elitebook claude-coordinator 467\r"),
            "positional machine/repo/issue trail the briefing; got: {cmd:?}",
        );
        assert!(
            cmd.contains("Plan-then-implement for issue #467"),
            "plan briefing must reference the issue; got: {cmd:?}",
        );
        assert!(
            cmd.contains("do not stop after planning"),
            "plan briefing must instruct continue-to-work; got: {cmd:?}",
        );
        assert!(cmd.ends_with('\r'), "must auto-run; got: {cmd:?}");
    }

    #[test]
    fn build_interactive_launch_cmd_review_mode_emits_review_of() {
        // #539: Review mode must emit `--review-of <work_aid>` and NOT
        // `--no-plan` — the reviewer role, not the implementer role.
        let cmd = build_interactive_launch_cmd(
            None,
            "elitebook",
            "claude-coordinator",
            539,
            InteractiveLaunchMode::Review,
            Some("abc-123"),
        );
        assert!(
            cmd.starts_with("coord assign --interactive "),
            "must invoke `coord assign --interactive`; got: {cmd:?}",
        );
        assert!(
            cmd.contains("--review-of abc-123"),
            "must pass --review-of <work_aid>; got: {cmd:?}",
        );
        assert!(
            cmd.contains("elitebook claude-coordinator 539"),
            "must pass positional machine/repo/issue; got: {cmd:?}",
        );
        assert!(
            !cmd.contains("--no-plan"),
            "review mode must NOT pass --no-plan; got: {cmd:?}",
        );
        assert!(cmd.ends_with('\r'), "must auto-run; got: {cmd:?}");
    }

    #[test]
    fn build_interactive_launch_cmd_review_mode_with_config_path() {
        // #539: Review mode with a config path injects --config before the flags.
        let cmd = build_interactive_launch_cmd(
            Some("/home/john/src/claude-coordinator/coordinator.yml"),
            "elitebook",
            "claude-coordinator",
            539,
            InteractiveLaunchMode::Review,
            Some("xyz-456"),
        );
        assert_eq!(
            cmd,
            "coord assign --config /home/john/src/claude-coordinator/coordinator.yml --interactive --review-of xyz-456 elitebook claude-coordinator 539\r",
        );
    }

    #[test]
    fn build_interactive_launch_cmd_quotes_repo_with_spaces() {
        // Defensive: a repo name that contains whitespace must be quoted
        // so the local shell sees it as a single argument.  Single
        // quotes also block shell-metachar interpretation.
        let cmd =
            build_interactive_launch_cmd(None, "m", "my repo", 42, InteractiveLaunchMode::Work, None);
        assert!(
            cmd.contains("'my repo' 42"),
            "repo with spaces must be single-quoted; got: {cmd:?}",
        );
    }

    #[test]
    fn build_interactive_launch_cmd_quotes_repo_with_shell_metachars() {
        // `$` / `;` / `&` / backticks must not be passed unquoted — they
        // would otherwise be interpreted by the local shell.
        let cmd = build_interactive_launch_cmd(
            None,
            "m",
            "evil;rm -rf /",
            1,
            InteractiveLaunchMode::Work,
            None,
        );
        assert!(
            cmd.contains("'evil;rm -rf /' 1"),
            "shell metachars must be quoted away; got: {cmd:?}",
        );
        // An embedded single quote is escaped via the standard '\'' trick.
        let cmd2 = build_interactive_launch_cmd(None, "m", "a'b", 2, InteractiveLaunchMode::Work, None);
        assert!(
            cmd2.contains(r"'a'\''b' 2"),
            "embedded single quotes must be escaped; got: {cmd2:?}",
        );
    }

    #[test]
    fn shell_quote_arg_passes_safe_strings_through() {
        // Common repo names (alphanumeric + `-`/`_`/`.`/`/`) are passed
        // through verbatim — no unnecessary quoting noise.
        assert_eq!(shell_quote_arg("claude-coordinator"), "claude-coordinator");
        assert_eq!(shell_quote_arg("coord_tui"), "coord_tui");
        assert_eq!(shell_quote_arg("v1.2.3"), "v1.2.3");
        assert_eq!(shell_quote_arg("a/b"), "a/b");
    }

    #[test]
    fn shell_quote_arg_quotes_empty_string() {
        // Empty argument must round-trip as `''` so the positional
        // argument still gets passed (and `coord` reports a useful error
        // rather than silently dropping it).
        assert_eq!(shell_quote_arg(""), "''");
    }

